class Solution:
    def connect(self, root: 'Optional[Node]') -> 'Optional[Node]':
        if not root:
            return root
        queue = [root]
        while queue:
            n = len(queue)
            nxt_level = []
            for i in range(n):
                node = queue[i]
                node.next = queue[i + 1] if i < n - 1 else None
                if node.left:
                    nxt_level.append(node.left)
                if node.right:
                    nxt_level.append(node.right)
            queue = nxt_level
        return root

